1	# Managed hosts: classic-laddie, johnny-walker, klaus-worker-0, makers-nix, weller
2	{
3	  description = "Cosmo: Fresh Start 2025";
4	
5	  inputs = {
6	    # The unstable branch is usually fine for desktops/home-servers,
7	    # but use "nixos-24.11" if you want rock-solid stability.
8	    nixpkgs.url = "github:nixos/nixpkgs/nixos-unstable";
9	
10	    agenix.url = "github:ryantm/agenix";
11	    agenix.inputs.nixpkgs.follows = "nixpkgs";
12	
13	    home-manager.url = "github:nix-community/home-manager";
14	    home-manager.inputs.nixpkgs.follows = "nixpkgs";
15	
16	    nixos-wsl.url = "github:nix-community/NixOS-WSL/main";
17	    nixos-wsl.inputs.nixpkgs.follows = "nixpkgs";
18	
19	    pre-commit-hooks = {
20	      url = "github:cachix/git-hooks.nix";
21	      inputs.nixpkgs.follows = "nixpkgs";
22	    };
23	
24	    nixos-generators = {
25	      url = "github:nix-community/nixos-generators";
26	      inputs.nixpkgs.follows = "nixpkgs";
27	    };
28	
29	    disko = {
30	      url = "github:nix-community/disko";
31	      inputs.nixpkgs.follows = "nixpkgs";
32	    };
33	
34	    klaus = {
35	      url = "github:patflynn/klaus";
36	      inputs.nixpkgs.follows = "nixpkgs";
37	    };
38	
39	    microvm = {
40	      url = "github:astro/microvm.nix";
41	      inputs.nixpkgs.follows = "nixpkgs";
42	    };
43	
44	    reel-life = {
45	      url = "github:gunk-dev/reel-life";
46	      inputs.nixpkgs.follows = "nixpkgs";
47	    };
48	
49	    github-relay = {
50	      url = "github:patflynn/github-relay";
51	      inputs.nixpkgs.follows = "nixpkgs";
52	    };
53	
54	    zen-browser.url = "github:0xc000022070/zen-browser-flake";
55	  };
56	
57	  outputs =
58	    {
59	      self,
60	      nixpkgs,
61	      home-manager,
62	      nixos-generators,
63	      agenix,
64	      pre-commit-hooks,
65	      klaus,
66	      microvm,
67	      reel-life,
68	      github-relay,
69	      ...
70	    }@inputs:
71	    let
72	      mkHome =
73	        {
74	          username,
75	          identity,
76	          baseModule,
77	          homeDirectory ? "/home/${username}",
78	        }:
79	        home-manager.lib.homeManagerConfiguration {
80	          pkgs = import nixpkgs {
81	            system = "x86_64-linux";
82	            config.allowUnfree = true;
83	          };
84	          extraSpecialArgs = { inherit inputs; };
85	          modules = [
86	            baseModule
87	            identity
88	            {
89	              home.username = username;
90	              home.homeDirectory = homeDirectory;
91	            }
92	          ];
93	        };
94	
95	      mkBootstrap =
96	        {
97	          system ? "x86_64-linux",
98	          hardware,
99	          disk ? null,
100	          hostName ? "nixos-bootstrap",
101	          hostId ? null,
102	          user ? "patrick",
103	          email ? "big.pat@gmail.com",
104	        }:
105	        nixpkgs.lib.nixosSystem {
106	          specialArgs = { inherit inputs; };
107	          modules = [
108	            { nixpkgs.hostPlatform = system; }
109	            hardware
110	            (if disk != null then disk else { })
111	            (if disk != null then inputs.disko.nixosModules.disko else { })
112	            ./modules/bootstrap.nix
113	            {
114	              networking.hostName = hostName;
115	              cosmo.user.default = user;
116	              cosmo.user.email = email;
117	            }
118	            (if hostId != null then { networking.hostId = hostId; } else { })
119	          ];
120	        };
121	    in
122	    {
123	      formatter.x86_64-linux = nixpkgs.legacyPackages.x86_64-linux.nixfmt-tree;
124	
125	      nixosConfigurations = {
126	        # Hostname: classic-laddie
127	        classic-laddie = nixpkgs.lib.nixosSystem {
128	          specialArgs = { inherit inputs; };
129	          modules = [
130	            { nixpkgs.hostPlatform = "x86_64-linux"; }
131	            ./hosts/classic-laddie/default.nix
132	            agenix.nixosModules.default
133	            microvm.nixosModules.host
134	            home-manager.nixosModules.home-manager
135	            (
136	              { config, ... }:
137	              {
138	                home-manager.useGlobalPkgs = true;
139	                home-manager.useUserPackages = true;
140	                home-manager.backupFileExtension = "backup";
141	                home-manager.extraSpecialArgs = { inherit inputs; };
142	                home-manager.users.${config.cosmo.user.default} = {
143	                  imports = [
144	                    ./home/server.nix
145	                    ./home/dev.nix
146	                    ./home/desktop.nix
147	                    ./home/identities/personal.nix
148	                    ./home/monitor-input.nix
149	                  ];
150	                  # Lock screen immediately on session start (auto-login is enabled)
151	                  wayland.windowManager.hyprland.settings.exec-once = [ "hyprlock" ];
152	                };
153	              }
154	            )
155	          ];
156	        };
157	
158	        # Bootstrap install target for classic-laddie (hostname: classic-laddie)
159	        classic-laddie-bootstrap = mkBootstrap {
160	          hardware = ./hosts/classic-laddie/hardware.nix;
161	          hostName = "classic-laddie";
162	          hostId = "8425e349";
163	        };
164	
165	        # Hostname: makers-nix
166	        makers-nix = nixpkgs.lib.nixosSystem {
167	          specialArgs = { inherit inputs; };
168	          modules = [
169	            { nixpkgs.hostPlatform = "x86_64-linux"; }
170	            ./hosts/makers-nix/default.nix
171	            inputs.nixos-wsl.nixosModules.wsl
172	            agenix.nixosModules.default
173	            home-manager.nixosModules.home-manager
174	            (
175	              { config, ... }:
176	              {
177	                home-manager.useGlobalPkgs = true;
178	                home-manager.useUserPackages = true;
179	                home-manager.backupFileExtension = "backup";
180	                home-manager.extraSpecialArgs = { inherit inputs; };
181	                home-manager.users.${config.cosmo.user.default} = {
182	                  imports = [
183	                    ./home/wsl.nix
184	                    ./home/identities/personal.nix
185	                  ];
186	                };
187	              }
188	            )
189	          ];
190	        };
191	
192	        # Hostname: johnny-walker
193	        johnny-walker = nixpkgs.lib.nixosSystem {
194	          specialArgs = { inherit inputs; };
195	          modules = [
196	            { nixpkgs.hostPlatform = "x86_64-linux"; }
197	            ./hosts/johnny-walker/default.nix
198	            agenix.nixosModules.default
199	            home-manager.nixosModules.home-manager
200	            (
201	              { config, ... }:
202	              {
203	                home-manager.useGlobalPkgs = true;
204	                home-manager.useUserPackages = true;
205	                home-manager.backupFileExtension = "backup";
206	                home-manager.extraSpecialArgs = { inherit inputs; };
207	                home-manager.users.${config.cosmo.user.default} = {
208	                  imports = [
209	                    ./home/desktop.nix
210	                    ./home/identities/personal.nix
211	                  ];
212	                };
213	              }
214	            )
215	          ];
216	        };
217	
218	        # Bootstrap install target for weller (hostname: weller)
219	        weller-bootstrap = mkBootstrap {
220	          hardware = ./hosts/weller/hardware.nix;
221	          disk = ./hosts/weller/disk-config.nix;
222	          hostName = "weller";
223	        };
224	
225	        # Hostname: weller (dual-boot Windows 11 + NixOS workstation)
226	        weller = nixpkgs.lib.nixosSystem {
227	          specialArgs = { inherit inputs; };
228	          modules = [
229	            { nixpkgs.hostPlatform = "x86_64-linux"; }
230	            ./hosts/weller/default.nix
231	            ./hosts/weller/disk-config.nix
232	            inputs.disko.nixosModules.disko
233	            agenix.nixosModules.default
234	            home-manager.nixosModules.home-manager
235	            (
236	              { config, ... }:
237	              {
238	                home-manager.useGlobalPkgs = true;
239	                home-manager.useUserPackages = true;
240	                home-manager.backupFileExtension = "backup";
241	                home-manager.extraSpecialArgs = { inherit inputs; };
242	                home-manager.users.${config.cosmo.user.default} = {
243	                  imports = [
244	                    ./home/desktop.nix
245	                    ./home/identities/personal.nix
246	                  ];
247	                };
248	              }
249	            )
250	          ];
251	        };
252	
253	        # Hostname: klaus-worker-0 (microVM worker for klaus agent)
254	        klaus-worker-0 = nixpkgs.lib.nixosSystem {
255	          specialArgs = { inherit inputs; };
256	          modules = [
257	            { nixpkgs.hostPlatform = "x86_64-linux"; }
258	            microvm.nixosModules.microvm
259	            ./modules/klaus-worker/default.nix
260	            {
261	              networking.hostName = "klaus-worker-0";
262	              klaus.worker = {
263	                vsockCid = 3;
264	                tapInterface = "vm-klaus-0";
265	                macAddress = "02:00:00:00:00:01";
266	              };
267	            }
268	          ];
269	        };
270	
271	      };
272	
273	      homeConfigurations = {
274	        # 1. Personal Debian (The classic)
275	        "personal" = mkHome {
276	          username = "patrick";
277	          identity = ./home/identities/personal.nix;
278	          baseModule = ./home/linux.nix;
279	        };
280	
281	        # 2. Work Debian (The new pure target)
282	        "paflynn@bushmills" = mkHome {
283	          username = "paflynn";
284	          identity = ./home/identities/work.nix;
285	          baseModule = ./home/linux.nix;
286	          homeDirectory = "/usr/local/google/home/paflynn";
287	        };
288	
289	        # 3. Personal Crostini
290	        "patrick@crostini" = mkHome {
291	          username = "patrick";
292	          identity = ./home/identities/personal.nix;
293	          baseModule = ./home/crostini.nix;
294	        };
295	
296	        # 4. Work Crostini
