# Managed hosts: classic-laddie, johnny-walker, klaus-worker-0, makers-nix, weller
{
  description = "Cosmo: Fresh Start 2025";

  inputs = {
    # The unstable branch is usually fine for desktops/home-servers,
    # but use "nixos-24.11" if you want rock-solid stability.
    nixpkgs.url = "github:nixos/nixpkgs/nixos-unstable";

    agenix.url = "github:ryantm/agenix";
    agenix.inputs.nixpkgs.follows = "nixpkgs";

    home-manager.url = "github:nix-community/home-manager";
    home-manager.inputs.nixpkgs.follows = "nixpkgs";

    nixos-wsl.url = "github:nix-community/NixOS-WSL/main";
    nixos-wsl.inputs.nixpkgs.follows = "nixpkgs";

    pre-commit-hooks = {
      url = "github:cachix/git-hooks.nix";
      inputs.nixpkgs.follows = "nixpkgs";
    };

    nixos-generators = {
      url = "github:nix-community/nixos-generators";
      inputs.nixpkgs.follows = "nixpkgs";
    };

    disko = {
      url = "github:nix-community/disko";
      inputs.nixpkgs.follows = "nixpkgs";
    };

    klaus = {
      url = "github:patflynn/klaus";
      inputs.nixpkgs.follows = "nixpkgs";
    };

    microvm = {
      url = "github:astro/microvm.nix";
      inputs.nixpkgs.follows = "nixpkgs";
    };

    reel-life = {
      url = "github:gunk-dev/reel-life";
      inputs.nixpkgs.follows = "nixpkgs";
    };

    github-relay = {
      url = "github:patflynn/github-relay";
      inputs.nixpkgs.follows = "nixpkgs";
    };

    zen-browser.url = "github:0xc000022070/zen-browser-flake";
  };

  outputs =
    {
      self,
      nixpkgs,
      home-manager,
      nixos-generators,
      agenix,
      pre-commit-hooks,
      klaus,
      microvm,
      reel-life,
      github-relay,
      ...
    }@inputs:
    let
      mkHome =
        {
          username,
          identity,
          baseModule,
          homeDirectory ? "/home/${username}",
        }:
        home-manager.lib.homeManagerConfiguration {
          pkgs = import nixpkgs {
            system = "x86_64-linux";
            config.allowUnfree = true;
          };
          extraSpecialArgs = { inherit inputs; };
          modules = [
            baseModule
            identity
            {
              home.username = username;
              home.homeDirectory = homeDirectory;
            }
          ];
        };

      mkBootstrap =
        {
          system ? "x86_64-linux",
          hardware,
          disk ? null,
          hostName ? "nixos-bootstrap",
          hostId ? null,
          user ? "patrick",
          email ? "big.pat@gmail.com",
        }:
        nixpkgs.lib.nixosSystem {
          specialArgs = { inherit inputs; };
          modules = [
            { nixpkgs.hostPlatform = system; }
            hardware
            (if disk != null then disk else { })
            (if disk != null then inputs.disko.nixosModules.disko else { })
            ./modules/bootstrap.nix
            {
              networking.hostName = hostName;
              cosmo.user.default = user;
              cosmo.user.email = email;
            }
            (if hostId != null then { networking.hostId = hostId; } else { })
          ];
        };
    in
    {
      formatter.x86_64-linux = nixpkgs.legacyPackages.x86_64-linux.nixfmt-tree;

      nixosConfigurations = {
        # Hostname: classic-laddie
        classic-laddie = nixpkgs.lib.nixosSystem {
          specialArgs = { inherit inputs; };
          modules = [
            { nixpkgs.hostPlatform = "x86_64-linux"; }
            ./hosts/classic-laddie/default.nix
            agenix.nixosModules.default
            microvm.nixosModules.host
            home-manager.nixosModules.home-manager
            (
              { config, ... }:
              {
                home-manager.useGlobalPkgs = true;
                home-manager.useUserPackages = true;
                home-manager.backupFileExtension = "backup";
                home-manager.extraSpecialArgs = { inherit inputs; };
                home-manager.users.${config.cosmo.user.default} = {
                  imports = [
                    ./home/server.nix
                    ./home/dev.nix
                    ./home/desktop.nix
                    ./home/identities/personal.nix
                    ./home/monitor-input.nix
                  ];
                  # Lock screen immediately on session start (auto-login is enabled)
                  wayland.windowManager.hyprland.settings.exec-once = [ "hyprlock" ];
                };
              }
            )
          ];
        };

        # Bootstrap install target for classic-laddie (hostname: classic-laddie)
        classic-laddie-bootstrap = mkBootstrap {
          hardware = ./hosts/classic-laddie/hardware.nix;
          hostName = "classic-laddie";
          hostId = "8425e349";
        };

        # Hostname: makers-nix
        makers-nix = nixpkgs.lib.nixosSystem {
          specialArgs = { inherit inputs; };
          modules = [
            { nixpkgs.hostPlatform = "x86_64-linux"; }
            ./hosts/makers-nix/default.nix
            inputs.nixos-wsl.nixosModules.wsl
            agenix.nixosModules.default
            home-manager.nixosModules.home-manager
            (
              { config, ... }:
              {
                home-manager.useGlobalPkgs = true;
                home-manager.useUserPackages = true;
                home-manager.backupFileExtension = "backup";
                home-manager.extraSpecialArgs = { inherit inputs; };
                home-manager.users.${config.cosmo.user.default} = {
                  imports = [
                    ./home/wsl.nix
                    ./home/identities/personal.nix
                  ];
                };
              }
            )
          ];
        };

        # Hostname: johnny-walker
        johnny-walker = nixpkgs.lib.nixosSystem {
          specialArgs = { inherit inputs; };
          modules = [
            { nixpkgs.hostPlatform = "x86_64-linux"; }
            ./hosts/johnny-walker/default.nix
            agenix.nixosModules.default
            home-manager.nixosModules.home-manager
            (
              { config, ... }:
              {
                home-manager.useGlobalPkgs = true;
                home-manager.useUserPackages = true;
                home-manager.backupFileExtension = "backup";
                home-manager.extraSpecialArgs = { inherit inputs; };
                home-manager.users.${config.cosmo.user.default} = {
                  imports = [
                    ./home/desktop.nix
                    ./home/identities/personal.nix
                  ];
                };
              }
            )
          ];
        };

        # Bootstrap install target for weller (hostname: weller)
        weller-bootstrap = mkBootstrap {
          hardware = ./hosts/weller/hardware.nix;
          disk = ./hosts/weller/disk-config.nix;
          hostName = "weller";
        };

        # Hostname: weller (dual-boot Windows 11 + NixOS workstation)
        weller = nixpkgs.lib.nixosSystem {
          specialArgs = { inherit inputs; };
          modules = [
            { nixpkgs.hostPlatform = "x86_64-linux"; }
            ./hosts/weller/default.nix
            ./hosts/weller/disk-config.nix
            inputs.disko.nixosModules.disko
            agenix.nixosModules.default
            home-manager.nixosModules.home-manager
            (
              { config, ... }:
              {
                home-manager.useGlobalPkgs = true;
                home-manager.useUserPackages = true;
                home-manager.backupFileExtension = "backup";
                home-manager.extraSpecialArgs = { inherit inputs; };
                home-manager.users.${config.cosmo.user.default} = {
                  imports = [
                    ./home/desktop.nix
                    ./home/identities/personal.nix
                  ];
                };
              }
            )
          ];
        };

        # Hostname: klaus-worker-0 (microVM worker for klaus agent)
        klaus-worker-0 = nixpkgs.lib.nixosSystem {
          specialArgs = { inherit inputs; };
          modules = [
            { nixpkgs.hostPlatform = "x86_64-linux"; }
            microvm.nixosModules.microvm
            ./modules/klaus-worker/default.nix
            {
              networking.hostName = "klaus-worker-0";
              klaus.worker = {
                vsockCid = 3;
                tapInterface = "vm-klaus-0";
                macAddress = "02:00:00:00:00:01";
              };
            }
          ];
        };

      };

      homeConfigurations = {
        # 1. Personal Debian (The classic)
        "personal" = mkHome {
          username = "patrick";
          identity = ./home/identities/personal.nix;
          baseModule = ./home/linux.nix;
        };

        # 2. Work Debian (The new pure target)
        "paflynn@bushmills" = mkHome {
          username = "paflynn";
          identity = ./home/identities/work.nix;
          baseModule = ./home/linux.nix;
          homeDirectory = "/usr/local/google/home/paflynn";
        };

        # 3. Personal Crostini
        "patrick@crostini" = mkHome {
          username = "patrick";
          identity = ./home/identities/personal.nix;
          baseModule = ./home/crostini.nix;
        };

        # 4. Work Crostini
        "paflynn@crostini" = mkHome {
          username = "paflynn";
          identity = ./home/identities/work.nix;
          baseModule = ./home/crostini.nix;
        };
      };

      packages.x86_64-linux = {
        # Expose zizmor here so CI can run it via 'nix run .#zizmor'
        # to avoid registry lookups and devShell hooks.
        zizmor = nixpkgs.legacyPackages.x86_64-linux.zizmor;
        klaus-worker-0 = self.nixosConfigurations.klaus-worker-0.config.microvm.declaredRunner;
        johnny-walker-image = nixos-generators.nixosGenerate {
          system = "x86_64-linux";
          specialArgs = { inherit inputs; };
          modules = [
            ./hosts/johnny-walker/default.nix
            agenix.nixosModules.default
            home-manager.nixosModules.home-manager
            (
              { config, ... }:
              {
                home-manager.useGlobalPkgs = true;
                home-manager.useUserPackages = true;
                home-manager.backupFileExtension = "backup";
                home-manager.extraSpecialArgs = { inherit inputs; };
                home-manager.users.${config.cosmo.user.default} = {
                  imports = [
                    ./home/desktop.nix
                    ./home/identities/personal.nix
                  ];
                };
              }
            )
          ];
          format = "qcow";
        };
      };

      checks.x86_64-linux = {
        pre-commit-check = pre-commit-hooks.lib.x86_64-linux.run {
          src = ./.;
          hooks = {
            nixfmt.enable = true;
            detect-private-keys.enable = true;
            zizmor = {
              enable = true;
              name = "zizmor";
              entry = "${nixpkgs.legacyPackages.x86_64-linux.zizmor}/bin/zizmor .";
              pass_filenames = false;
            };
          };
        };
      };

      devShells.x86_64-linux.default =
        let
          pkgs = nixpkgs.legacyPackages.x86_64-linux;
        in
        pkgs.mkShell {
          inherit (self.checks.x86_64-linux.pre-commit-check) shellHook;
          buildInputs = self.checks.x86_64-linux.pre-commit-check.enabledPackages;
        };
    };
}
